import org.junit.jupiter.api.*;
import org.junit.jupiter.params.*;
import org.junit.jupiter.params.provider.*;
import org.junit.jupiter.api.extension.*;

import java.util.Collection;

class SomeTest {
    @BeforeAll
    static void setupClass() {}

    @BeforeEach
    void setup() {}

    @Test
    void testFoo() {}

    @RepeatedTest(10)
    void testRepeated() {}

    @TestFactory
    Collection<DynamicTest> ruleTests() {}

    @TestTemplate
    @ExtendWith(MyTestTemplateInvocationContextProvider.class)
    void testTemplate(String param) {}

    @ParameterizedTest
    @ValueSource(strings = { "abc", "def" })
    void testParameterized(String param) {}

    @AfterEach
    void teardown() {}

    @AfterAll
    static void teardownClass() {}

    private class MyTestTemplateInvocationContextProvider implements org.junit.jupiter.api.extension.TestTemplateInvocationContextProvider {
        @Override
        public boolean supportsTestTemplate(ExtensionContext context) {
            return true;
        }

        @Override
        public Stream<TestTemplateInvocationContext> provideTestTemplateInvocationContexts(ExtensionContext context) {
            return Stream.of();
        }
    }
}

import org.junit.Test;
import org.junit.Before;
import org.junit.BeforeClass;
import org.junit.After;
import org.junit.AfterClass;

public class SomeTest {
    @BeforeClass
    public static void setupClass() {}

    @Before
    public void setup() {}

    @Test
    public void testFoo() {}

    @After
    public void teardown() {}

    @AfterClass
    public void teardownClass() {}
}

import org.testng.annotations.BeforeSuite;
import org.testng.annotations.BeforeTest;
import org.testng.annotations.BeforeClass;
import org.testng.annotations.BeforeGroups;
import org.testng.annotations.BeforeMethod;
import org.testng.annotations.Test;
import org.testng.annotations.AfterMethod;
import org.testng.annotations.AfterGroups;
import org.testng.annotations.AfterClass;
import org.testng.annotations.AfterTest;
import org.testng.annotations.AfterSuite;

public class TestNGCompleteTest {

    @BeforeSuite
    public void beforeSuite() {}

    @BeforeTest
    public void beforeTest() {}

    @BeforeClass
    public void beforeClass() {}

    @BeforeGroups(groups = { "functional" })
    public void beforeGroups() {}

    @BeforeMethod
    public void beforeMethod() {}

    @Test
    public void standardTest() {}

    @AfterMethod
    public void afterMethod() {}

    @AfterGroups(groups = { "functional" })
    public void afterGroups() {}

    @AfterClass
    public void afterClass() {}

    @AfterTest
    public void afterTest() {}

    @AfterSuite
    public void afterSuite() {}
}

